import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  forwardRef,
  InjectionToken,
  OnDestroy,
  signal,
  viewChild,
  ViewEncapsulation,
} from '@angular/core';

/**
 * Conversation — scrollable container that auto-sticks to the bottom while
 * new messages arrive, matching React `Conversation` (which wraps the
 * `use-stick-to-bottom` library).
 *
 * Implementation notes:
 * - Uses a self-contained scroll-and-resize observer (no JS lib dep).
 * - Exposes `isAtBottom` signal + `scrollToBottom()` via DI so the
 *   `ConversationScrollButton` companion can stay decoupled.
 * - Bottom threshold of 24px matches "feels stuck" in chat UIs.
 */
export interface ConversationState {
  readonly isAtBottom: () => boolean;
  scrollToBottom(behavior?: ScrollBehavior): void;
}

export const CONVERSATION = new InjectionToken<ConversationState>(
  'ConversationState',
);

const STICK_THRESHOLD_PX = 24;

@Component({
  selector: 'conversation',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div #scroller class="size-full overflow-y-auto" (scroll)="onScroll()">
      <ng-content />
    </div>
  `,
  host: {
    role: 'log',
    class: 'relative flex-1 overflow-y-hidden',
  },
  providers: [
    {
      provide: CONVERSATION,
      useExisting: forwardRef(() => Conversation),
    },
  ],
})
export class Conversation
  implements AfterViewInit, OnDestroy, ConversationState
{
  protected readonly scroller =
    viewChild.required<ElementRef<HTMLDivElement>>('scroller');

  private readonly _isAtBottom = signal(true);
  readonly isAtBottom = () => this._isAtBottom();

  private resizeObserver?: ResizeObserver;
  private mutationObserver?: MutationObserver;

  ngAfterViewInit(): void {
    const el = this.scroller().nativeElement;

    // Initial scroll to bottom.
    this.scrollToBottom('auto');

    // Auto-stick when content grows.
    if (typeof ResizeObserver !== 'undefined') {
      this.resizeObserver = new ResizeObserver(() => {
        if (this._isAtBottom()) {
          this.scrollToBottom('smooth');
        }
      });
      // Observe both the scroller and its first child (the projected content).
      this.resizeObserver.observe(el);
      const child = el.firstElementChild;
      if (child) this.resizeObserver.observe(child);
    }

    // Auto-stick when new nodes are added even without size change (rare).
    if (typeof MutationObserver !== 'undefined') {
      this.mutationObserver = new MutationObserver(() => {
        if (this._isAtBottom()) {
          this.scrollToBottom('smooth');
        }
      });
      this.mutationObserver.observe(el, {
        childList: true,
        subtree: true,
      });
    }
  }

  ngOnDestroy(): void {
    this.resizeObserver?.disconnect();
    this.mutationObserver?.disconnect();
  }

  protected onScroll(): void {
    const el = this.scroller().nativeElement;
    const distance = el.scrollHeight - el.scrollTop - el.clientHeight;
    this._isAtBottom.set(distance <= STICK_THRESHOLD_PX);
  }

  scrollToBottom(behavior: ScrollBehavior = 'smooth'): void {
    const el = this.scroller().nativeElement;
    el.scrollTo({ top: el.scrollHeight, behavior });
    this._isAtBottom.set(true);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
} from '@angular/core';

/**
 * ConversationContent — inner flex column for the message list.
 *
 * Mirrors React `ConversationContent`. Visual sibling of the scroll button.
 */
@Component({
  selector: 'conversation-content',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    class: 'flex flex-col gap-8 p-4',
  },
})
export class ConversationContent {}

import {
  ChangeDetectionStrategy,
  Component,
  input,
  ViewEncapsulation,
} from '@angular/core';

/**
 * ConversationEmptyState — placeholder shown when no messages exist.
 *
 * Mirrors React `ConversationEmptyState`. Projects custom content; falls
 * back to title + description + optional projected icon (via the `[icon]`
 * slot).
 */
@Component({
  selector: 'conversation-empty-state',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <ng-content select="[icon]" />
    <ng-content>
      <div class="space-y-1">
        <h3 class="font-medium text-sm">{{ title() }}</h3>
        @if (description()) {
          <p class="text-muted-foreground text-sm">{{ description() }}</p>
        }
      </div>
    </ng-content>
  `,
  host: {
    class:
      'flex size-full flex-col items-center justify-center gap-3 p-8 text-center',
  },
})
export class ConversationEmptyState {
  readonly title = input<string>('No messages yet');
  readonly description = input<string>(
    'Start a conversation to see messages here',
  );
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  ViewEncapsulation,
} from '@angular/core';

import { CONVERSATION } from './conversation';

/**
 * ConversationScrollButton — "scroll to bottom" pill that appears only when
 * the user has scrolled up. Mirrors React `ConversationScrollButton`.
 *
 * Reads `isAtBottom` and calls `scrollToBottom()` on the parent
 * Conversation via DI.
 */
@Component({
  selector: 'conversation-scroll-button',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @if (visible()) {
      <button
        type="button"
        (click)="scroll()"
        class="absolute bottom-4 left-[50%] inline-flex size-9 -translate-x-1/2 items-center justify-center rounded-full border bg-background text-foreground shadow-sm transition-colors hover:bg-accent hover:text-accent-foreground"
        aria-label="Scroll to bottom"
      >
        <svg
          width="16"
          height="16"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          stroke-width="2"
          stroke-linecap="round"
          stroke-linejoin="round"
          aria-hidden="true"
        >
          <path d="M12 5v14M19 12l-7 7-7-7" />
        </svg>
      </button>
    }
  `,
})
export class ConversationScrollButton {
  private readonly state = inject(CONVERSATION);
  protected readonly visible = computed(() => !this.state.isAtBottom());

  protected scroll(): void {
    this.state.scrollToBottom('smooth');
  }
}

export { Conversation, CONVERSATION } from './conversation';
export type { ConversationState } from './conversation';
export { ConversationContent } from './conversation-content';
export { ConversationEmptyState } from './conversation-empty-state';
export { ConversationScrollButton } from './conversation-scroll-button';
